mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.avatar, u.status, u.created_at AS createdAt, r.id AS roleId, r.role_name AS roleName, (SELECT COUNT(*) FROM article a WHERE a.user_id = u.id AND a.status != '4') AS articleCount FROM user u LEFT JOIN user_role ur ON ur.user_id = u.id LEFT JOIN role r ON r.id = ur.role_id
AND (u.username LIKE CONCAT('%', #{req.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{req.keyword}, '%') OR u.email LIKE CONCAT('%', #{req.keyword}, '%'))
AND u.status = #{req.status}
AND ur.role_id = #{req.roleId}
ORDER BY u.created_at DESC LIMIT #{req.pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT u.id) FROM user u LEFT JOIN user_role ur ON ur.user_id = u.id
AND (u.username LIKE CONCAT('%', #{req.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{req.keyword}, '%') OR u.email LIKE CONCAT('%', #{req.keyword}, '%'))
AND u.status = #{req.status}
AND ur.role_id = #{req.roleId}
